:root {
  --bg-board: #1e1a14;
  --bg-card: #2c2519;
  --bg-featured: #3a2e1c;
  --border-card: #4a3e2a;
  --border-featured: #c9a84c;
  --text-primary: #f0e6cc;
  --text-secondary: #a8936a;
  --text-day: #c9a84c;
  --text-price: #f0e6cc;
  --badge-pick-bg: #c9a84c;
  --badge-pick-text: #1e1a14;
  --badge-veg-bg: #3a5e3a;
  --badge-veg-text: #a8d4a8;
  --badge-fish-bg: #1e3a5e;
  --badge-fish-text: #a8c8f0;
  --badge-pop-bg: #5e2a2a;
  --badge-pop-text: #f0a8a8;
  --footer-text: #6e5e3e;
  --tag-bg: #c9a84c;
  --tag-text: #1e1a14;
}

.board {
  background-color: var(--bg-board);
  border-radius: 12px;
  padding: 20px;
  width: 520px;
  max-width: 520px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.board-header {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.board-tag {
  background-color: var(--tag-bg);
  color: var(--tag-text);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  padding: 3px 8px;
  border-radius: 4px;
  width: fit-content;
}

.board-title {
  font-size: 24px;
  font-weight: 700;
  color: var(--text-primary);
  margin: 0;
  line-height: 1.2;
}

.board-subtitle {
  font-size: 12px;
  color: var(--text-secondary);
  margin: 0;
  line-height: 1.4;
}

.specials-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
}

.special-card {
  background-color: var(--bg-card);
  border: 1px solid var(--border-card);
  border-radius: 8px;
  padding: 12px;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.special-card.featured {
  background-color: var(--bg-featured);
  border-color: var(--border-featured);
}

.card-day {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--text-day);
}

.card-name {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
  line-height: 1.3;
}

.card-desc {
  font-size: 12px;
  color: var(--text-secondary);
  line-height: 1.4;
  flex: 1;
}

.card-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-top: 6px;
}

.card-badge {
  font-size: 10px;
  font-weight: 600;
  padding: 2px 7px;
  border-radius: 20px;
  background-color: var(--badge-pick-bg);
  color: var(--badge-pick-text);
}

.card-badge.veg {
  background-color: var(--badge-veg-bg);
  color: var(--badge-veg-text);
}

.card-badge.fish {
  background-color: var(--badge-fish-bg);
  color: var(--badge-fish-text);
}

.card-badge.pop {
  background-color: var(--badge-pop-bg);
  color: var(--badge-pop-text);
}

.card-price {
  font-size: 16px;
  font-weight: 700;
  color: var(--text-price);
}

.board-footer {
  border-top: 1px solid var(--border-card);
  padding-top: 10px;
  text-align: center;
}

.footer-note {
  font-size: 11px;
  color: var(--footer-text);
  letter-spacing: 0.04em;
}
